const body = $json.body || $json;

if (body.sender_id && body.message_text) {
  return [{
    json: {
      sender_id: body.sender_id,
      recipient_id: body.recipient_id || null,
      instagram_username: body.instagram_username || null,
      message_text: body.message_text,
      raw_event: body.raw_event || body,
      entry_id: body.entry_id || null,
      object: body.object || 'internal'
    }
  }];
}

const output = [];
for (const entry of (body.entry || [])) {
  for (const messaging of (entry.messaging || [])) {
    const senderId = messaging?.sender?.id;
    const text = messaging?.message?.text;
    if (!senderId || !text) continue;
    if (messaging?.message?.is_echo) continue;
    output.push({
      json: {
        sender_id: senderId,
        recipient_id: messaging?.recipient?.id || null,
        instagram_username: messaging?.sender?.username || null,
        message_text: text,
        raw_event: messaging,
        entry_id: entry.id || null,
        object: body.object || null
      }
    });
  }
}

if (output.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_messages' } }];
}

return output;

const error = $json;
const inputData = $('Has Valid Message').item.json || {};
const fallbackReply = 'Mesajınızı aldık, kontrol edip size en kısa sürede dönüş yapacağız.';
console.error('Booking API error for sender_id=' + (inputData.sender_id || 'unknown'), JSON.stringify(error));
return [{
  json: {
    should_reply: true,
    error: true,
    error_message: 'backend_processing_failed',
    sender_id: inputData.sender_id || null,
    reply_text: fallbackReply,
    handoff: true,
    decision_path: ['n8n:error_fallback']
  }
}];
